 23→const GITHUB_PROMOTION_PATH_PREFIX =
 24→  '/Nagi-ovo/gemini-voyager/raw/main/docs/public/assets/promotion/';
 25→const RAW_GITHUBUSERCONTENT_PROMOTION_PATH_PREFIX =
 26→  '/Nagi-ovo/gemini-voyager/main/docs/public/assets/promotion/';
