 43→function getRuntimeUrl(path: string): string | null {
 44→  try {
 45→    const runtime = (
 46→      globalThis as typeof globalThis & {
 47→        browser?: { runtime?: { getURL?: (assetPath: string) => string } };
 48→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 49→      }
 50→    ).browser?.runtime;
 51→    const fallbackRuntime = (
 52→      globalThis as typeof globalThis & {
 53→        chrome?: { runtime?: { getURL?: (assetPath: string) => string } };
 54→      }
 55→    ).chrome?.runtime;
 56→    const getUrl = runtime?.getURL ?? fallbackRuntime?.getURL;
 57→    return typeof getUrl === 'function' ? getUrl(path) : null;
 58→  } catch {
 59→    return null;
 60→  }
 61→}
 62→
 63→function extractPromotionRuntimePath(url: URL): string | null {
 64→  const host = url.hostname.toLowerCase();
 65→  const pathname = url.pathname;
 66→  const isGithubPromotionImage =
 67→    (host === 'github.com' && pathname.startsWith(GITHUB_PROMOTION_PATH_PREFIX)) ||
 68→    (host === 'raw.githubusercontent.com' &&
 69→      pathname.startsWith(RAW_GITHUBUSERCONTENT_PROMOTION_PATH_PREFIX));
 70→  if (!isGithubPromotionImage) return null;
 71→
 72→  const filename = pathname.split('/').pop();
 73→  return filename ? getPromotionRuntimePath(filename) : null;
 74→}
 75→
 76→export function resolveChangelogImageUrl(
 77→  url: string,
 78→  runtimeUrlResolver: (path: string) => string | null = getRuntimeUrl,
 79→): string {
 80→  try {
 81→    const parsed = new URL(url);
 82→    const runtimePath = extractPromotionRuntimePath(parsed);
 83→    if (!runtimePath) return url;
 84→
 85→    const runtimeUrl = runtimeUrlResolver(runtimePath);
 86→    return runtimeUrl ?? url;
 87→  } catch {
 88→    return url;
 89→  }
 90→}
 91→
 92→export function rewriteChangelogImageUrls(
 93→  markdown: string,
 94→  runtimeUrlResolver: (path: string) => string | null = getRuntimeUrl,
 95→  shouldRewrite: boolean = true,
 96→): string {
 97→  if (!shouldRewrite) return markdown;
 98→
 99→  return markdown.replace(MARKDOWN_IMAGE_URL_REGEX, (full, alt, url) => {
100→    const resolvedUrl = resolveChangelogImageUrl(url, runtimeUrlResolver);
101→    if (resolvedUrl === url) return full;
102→    return `![${alt}](${resolvedUrl})`;
103→  });
104→}
