106→/**
107→ * Strip optional front matter (--- ... ---) from markdown.
108→ */
109→function stripFrontMatter(raw: string): string {
110→  const match = raw.match(/^---\r?\n[\s\S]*?\r?\n---\r?\n([\s\S]*)$/);
111→  return match ? match[1] : raw;
112→}
