114→/**
115→ * Extract the section matching the user's language from a multi-language
116→ * markdown file. Falls back to 'en' if the requested language is missing.
117→ */
118→export function extractLocalizedContent(raw: string, lang: AppLanguage): string {
119→  const body = stripFrontMatter(raw);
120→
121→  // Split by <!-- lang:xx --> markers
122→  const sections = new Map<string, string>();
123→  const parts = body.split(/<!--\s*lang:(\w+)\s*-->/);
124→
125→  // parts[0] is text before the first marker (usually empty)
126→  // parts[1] = lang code, parts[2] = content, parts[3] = lang code, etc.
127→  for (let i = 1; i < parts.length; i += 2) {
128→    const langCode = parts[i];
129→    const content = parts[i + 1]?.trim() ?? '';
130→    if (langCode && content) {
131→      sections.set(langCode, content);
132→    }
133→  }
134→
135→  return sections.get(lang) ?? sections.get('en') ?? '';
136→}
