138→/**
139→ * Translate a key using an explicit language, bypassing cachedLanguage.
140→ * This avoids race conditions when initI18n() hasn't finished yet.
141→ */
142→function t(key: TranslationKey, lang: AppLanguage): string {
143→  return TRANSLATIONS[lang][key] ?? TRANSLATIONS.en[key] ?? key;
