168→/**
169→ * Show a full-screen lightbox preview for the given image.
170→ */
171→function showImageLightbox(src: string, alt: string): void {
172→  const lightbox = document.createElement('div');
173→  lightbox.className = 'gv-changelog-lightbox';
174→
175→  const img = document.createElement('img');
176→  img.src = src;
177→  img.alt = alt;
178→  img.className = 'gv-changelog-lightbox-img';
179→
180→  lightbox.appendChild(img);
181→  document.body.appendChild(lightbox);
182→
183→  const close = (): void => {
184→    lightbox.remove();
185→    document.removeEventListener('keydown', onKeyDown);
186→  };
187→
188→  const onKeyDown = (e: KeyboardEvent): void => {
189→    if (e.key === 'Escape') close();
190→  };
191→
192→  lightbox.addEventListener('click', close);
193→  document.addEventListener('keydown', onKeyDown);
194→}
